// Minimal replacement for https://unpkg.com/coi-serviceworker@latest/coi-serviceworker.min.js
// Registers a Service Worker from the same origin to enable COOP/COEP headers on static resources.
(async () => {
  if (!('serviceWorker' in navigator)) return;

  try {
    const regs = await navigator.serviceWorker.getRegistrations();
    const already = regs.some((r) => r.active && r.active.scriptURL.endsWith('/coi-serviceworker.js'));
    if (already) return; // nothing to do

    await navigator.serviceWorker.register('/coi-serviceworker.js', { scope: '/' });
    console.log('[COI] ServiceWorker registrado desde /coi-serviceworker.js');
  } catch (err) {
    console.warn('[COI] No se pudo registrar el ServiceWorker', err);
  }
})();
